UNDERTOW-1337 File descriptor leak cause JarURLConnection.getLastModified()

Here is the root cause:
The bug is caused by a file descriptor leak when using `JarURLConnection.getLastModified()`, which does not properly manage the connection, leading to unclosed resources and potential exhaustion of file descriptors. This occurs particularly when the connection is cached and not explicitly closed after use.

Here is the patch:
 import java.io.IOException;
 import java.io.InputStream;
+import java.net.JarURLConnection;
 import java.net.URISyntaxException;
 import java.net.URL;

     private void openConnection() {
         if (!connectionOpened) {
             connectionOpened = true;
             URLConnection connection = null;
             try {
                 try {
                     connection = url.openConnection();
                 } catch (IOException e) {
                     lastModified = null;
                     contentLength = null;
                     return;
                 }
-                lastModified =  new Date(connection.getLastModified());
+                if (url.getProtocol().equals("jar")) {
+                    connection.setUseCaches(false);
+                    URL jar = ((JarURLConnection) connection).getJarFileURL();
+                    lastModified = new Date(new File(jar.getFile()).lastModified());
+                } else {
+                    lastModified = new Date(connection.getLastModified());
+                }
                 contentLength = connection.getContentLengthLong();
             } finally {
                 if (connection != null) {
                     try {
                         IoUtils.safeClose(connection.getInputStream());
                     } catch (IOException e) {
                         //ignore
                     }
                 }
             }
         }
     }



